const events = $input.all();
const requestDate = $('Webhook').first().json.body?.date || '';
const resource = $('Webhook').first().json.body?.resource || 'slot';

// Build busy slots from existing events
const busySlots = events
  .filter(e => e.json.start)
  .map(e => ({
    start: e.json.start?.dateTime || e.json.start?.date,
    end: e.json.end?.dateTime || e.json.end?.date,
    title: e.json.summary || 'Busy'
  }));

// Generate all 30-min slots from 9am to 6pm
const allSlots = [];
for (let h = 9; h < 18; h++) {
  for (let m = 0; m < 60; m += 30) {
    const timeStr = `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;
    const isBusy = busySlots.some(bs => {
      const bsTime = (bs.start || '').split('T')[1]?.slice(0,5);
      return bsTime === timeStr;
    });
    if (!isBusy) allSlots.push(timeStr);
  }
}

const freeCount = allSlots.length;
const tamilMsg = freeCount > 0
  ? `${requestDate} அன்று ${freeCount} slots கிடைக்கின்றன. முதல் கிடைக்கும் நேரம்: ${allSlots[0]}. ${allSlots.slice(0,3).join(', ')} ஆகிய நேரங்களில் appointment வரலாம்.`
  : `மன்னிக்கவும், ${requestDate} அன்று அனைத்து slots நிறைந்துவிட்டன.`;

const engMsg = freeCount > 0
  ? `${freeCount} slots available on ${requestDate}. Earliest: ${allSlots[0]}. Options: ${allSlots.slice(0,3).join(', ')}.`
  : `Sorry, all slots on ${requestDate} are full.`;

return [{
  json: {
    date: requestDate,
    available: freeCount > 0,
    free_slots: allSlots.slice(0, 6),
    busy_count: busySlots.length,
    free_count: freeCount,
    message_ta: tamilMsg,
    message_en: engMsg
  }
}];
